3723         assert(RK.AttrKind == CanonRK.AttrKind);
3724         if (BOI.End - BOI.Begin > 0)
3725           II->op_begin()[BOI.Begin].set(CanonRK.WasOn);
3726         if (BOI.End - BOI.Begin > 1)
3727           II->op_begin()[BOI.Begin + 1].set(ConstantInt::get(
3728               Type::getInt64Ty(II->getContext()), CanonRK.ArgValue));
3729         if (RK.WasOn)
3730           Worklist.pushValue(RK.WasOn);
3731         return II;
3732       }
3733     }
3734 
3735     // If there is a dominating assume with the same condition as this one,
3736     // then this one is redundant, and should be removed.
3737     KnownBits Known(1);
3738     computeKnownBits(IIOperand, Known, II);
3739     if (Known.isAllOnes() && isAssumeWithEmptyBundle(cast<AssumeInst>(*II)))
3740       return eraseInstFromFunction(*II);
3741 
3742     // assume(false) is unreachable.
3743     if (match(IIOperand, m_CombineOr(m_Zero(), m_Undef()))) {
3744       CreateNonTerminatorUnreachable(II);
3745       return eraseInstFromFunction(*II);
3746     }
3747 
3748     // Update the cache of affected values for this assumption (we might be
3749     // here because we just simplified the condition).
3750     AC.updateAffectedValues(cast<AssumeInst>(II));
3751     break;
3752   }
3753   case Intrinsic::experimental_guard: {
3754     // Is this guard followed by another guard?  We scan forward over a small
3755     // fixed window of instructions to handle common cases with conditions
3756     // computed between guards.
3757     Instruction *NextInst = II->getNextNode();
3758     for (unsigned i = 0; i < GuardWideningWindow; i++) {
3759       // Note: Using context-free form to avoid compile time blow up
3760       if (!isSafeToSpeculativelyExecute(NextInst))
3761         break;
3762       NextInst = NextInst->getNextNode();
3763     }
3764     Value *NextCond = nullptr;
3765     if (match(NextInst,
3766               m_Intrinsic<Intrinsic::experimental_guard>(m_Value(NextCond)))) {
3767       Value *CurrCond = II->getArgOperand(0);
3768 
3769       // Remove a guard that it is immediately preceded by an identical guard.
3770       // Otherwise canonicalize guard(a); guard(b) -> guard(a & b).
3771       if (CurrCond != NextCond) {
3772         Instruction *MoveI = II->getNextNode();
3773         while (MoveI != NextInst) {
3774           auto *Temp = MoveI;
3775           MoveI = MoveI->getNextNode();
3776           Temp->moveBefore(II->getIterator());
3777         }
3778         replaceOperand(*II, 0, Builder.CreateAnd(CurrCond, NextCond));
3779       }
3780       eraseInstFromFunction(*NextInst);
3781       return II;
3782     }
3783     break;
3784   }
3785   case Intrinsic::vector_insert: {
3786     Value *Vec = II->getArgOperand(0);
3787     Value *SubVec = II->getArgOperand(1);
3788     Value *Idx = II->getArgOperand(2);
3789     auto *DstTy = dyn_cast<FixedVectorType>(II->getType());
3790     auto *VecTy = dyn_cast<FixedVectorType>(Vec->getType());
3791     auto *SubVecTy = dyn_cast<FixedVectorType>(SubVec->getType());
3792 
3793     // Only canonicalize if the destination vector, Vec, and SubVec are all
3794     // fixed vectors.
3795     if (DstTy && VecTy && SubVecTy) {
3796       unsigned DstNumElts = DstTy->getNumElements();
3797       unsigned VecNumElts = VecTy->getNumElements();
3798       unsigned SubVecNumElts = SubVecTy->getNumElements();
3799       unsigned IdxN = cast<ConstantInt>(Idx)->getZExtValue();
3800 
3801       // An insert that entirely overwrites Vec with SubVec is a nop.
3802       if (VecNumElts == SubVecNumElts)
3803         return replaceInstUsesWith(CI, SubVec);
3804 
3805       // Widen SubVec into a vector of the same width as Vec, since
3806       // shufflevector requires the two input vectors to be the same width.
3807       // Elements beyond the bounds of SubVec within the widened vector are
3808       // undefined.
3809       SmallVector<int, 8> WidenMask;
3810       unsigned i;
3811       for (i = 0; i != SubVecNumElts; ++i)
3812         WidenMask.push_back(i);
3813       for (; i != VecNumElts; ++i)
3814         WidenMask.push_back(PoisonMaskElem);
3815 
3816       Value *WidenShuffle = Builder.CreateShuffleVector(SubVec, WidenMask);
3817 
3818       SmallVector<int, 8> Mask;
3819       for (unsigned i = 0; i != IdxN; ++i)
3820         Mask.push_back(i);
3821       for (unsigned i = DstNumElts; i != DstNumElts + SubVecNumElts; ++i)
3822         Mask.push_back(i);
3823       for (unsigned i = IdxN + SubVecNumElts; i != DstNumElts; ++i)
3824         Mask.push_back(i);
3825 
3826       Value *Shuffle = Builder.CreateShuffleVector(Vec, WidenShuffle, Mask);
3827       return replaceInstUsesWith(CI, Shuffle);
3828     }
3829     break;
3830   }
3831   case Intrinsic::vector_extract: {
3832     Value *Vec = II->getArgOperand(0);
3833     Value *Idx = II->getArgOperand(1);
3834 
3835     Type *ReturnType = II->getType();
3836     // (extract_vector (insert_vector InsertTuple, InsertValue, InsertIdx),
3837     // ExtractIdx)
3838     unsigned ExtractIdx = cast<ConstantInt>(Idx)->getZExtValue();
3839     Value *InsertTuple, *InsertIdx, *InsertValue;
3840     if (match(Vec, m_Intrinsic<Intrinsic::vector_insert>(m_Value(InsertTuple),
3841                                                          m_Value(InsertValue),
3842                                                          m_Value(InsertIdx))) &&
3843         InsertValue->getType() == ReturnType) {
3844       unsigned Index = cast<ConstantInt>(InsertIdx)->getZExtValue();
3845       // Case where we get the same index right after setting it.
3846       // extract.vector(insert.vector(InsertTuple, InsertValue, Idx), Idx) -->
3847       // InsertValue
3848       if (ExtractIdx == Index)
3849         return replaceInstUsesWith(CI, InsertValue);
3850       // If we are getting a different index than what was set in the
3851       // insert.vector intrinsic. We can just set the input tuple to the one up
3852       // in the chain. extract.vector(insert.vector(InsertTuple, InsertValue,
3853       // InsertIndex), ExtractIndex)
3854       // --> extract.vector(InsertTuple, ExtractIndex)
3855       else
3856         return replaceOperand(CI, 0, InsertTuple);
3857     }
3858 
3859     auto *DstTy = dyn_cast<VectorType>(ReturnType);
3860     auto *VecTy = dyn_cast<VectorType>(Vec->getType());
3861 
3862     if (DstTy && VecTy) {
3863       auto DstEltCnt = DstTy->getElementCount();
3864       auto VecEltCnt = VecTy->getElementCount();
3865       unsigned IdxN = cast<ConstantInt>(Idx)->getZExtValue();
3866 
3867       // Extracting the entirety of Vec is a nop.
3868       if (DstEltCnt == VecTy->getElementCount()) {
3869         replaceInstUsesWith(CI, Vec);
3870         return eraseInstFromFunction(CI);
3871       }
3872 
3873       // Only canonicalize to shufflevector if the destination vector and
3874       // Vec are fixed vectors.
3875       if (VecEltCnt.isScalable() || DstEltCnt.isScalable())
3876         break;
3877 
3878       SmallVector<int, 8> Mask;
3879       for (unsigned i = 0; i != DstEltCnt.getKnownMinValue(); ++i)
3880         Mask.push_back(IdxN + i);
3881 
3882       Value *Shuffle = Builder.CreateShuffleVector(Vec, Mask);
3883       return replaceInstUsesWith(CI, Shuffle);
3884     }
3885     break;
3886   }
3887   case Intrinsic::experimental_vp_reverse: {
3888     Value *X;
3889     Value *Vec = II->getArgOperand(0);
3890     Value *Mask = II->getArgOperand(1);
3891     if (!match(Mask, m_AllOnes()))
3892       break;
3893     Value *EVL = II->getArgOperand(2);
3894     // TODO: Canonicalize experimental.vp.reverse after unop/binops?
3895     // rev(unop rev(X)) --> unop X
3896     if (match(Vec,
3897               m_OneUse(m_UnOp(m_Intrinsic<Intrinsic::experimental_vp_reverse>(
3898                   m_Value(X), m_AllOnes(), m_Specific(EVL)))))) {
3899       auto *OldUnOp = cast<UnaryOperator>(Vec);
