371 /// Returns the next power of two (in 64-bits) that is strictly greater than A.
372 /// Returns zero on overflow.
373 constexpr uint64_t NextPowerOf2(uint64_t A) {
374   A |= (A >> 1);
375   A |= (A >> 2);
376   A |= (A >> 4);
377   A |= (A >> 8);
378   A |= (A >> 16);
379   A |= (A >> 32);
380   return A + 1;
